-- MODULE config DATE 20260607
-- Seed default public FAQ Q&A items for admin-editable `public_faq.ITEMS`.

BEGIN;

UPDATE public.module_configs
SET config = config || jsonb_build_object(
	'ITEMS',
	'[{"question":"Why switch from Buffer or Hootsuite?","answer":"Buffer and Hootsuite charge $75–$200/month for enterprise feature most teams never use. OpenQuok covers the same UI scheduling basics including connect channels, compose, calendar, multi-channel publish. We also cover agent-first features like workspaces, integrations, and API/CLI access. Same workflow when you post by hand; built for when agents do the work. Less cost, less clutter, and real support from Meta and OpenQuok team."},{"question":"Can I try OpenQuok for free?","answer":"Yes. OpenQuok offers a 7-day free trial. You can create an account and start today!"},{"question":"Can I self-host OpenQuok?","answer":"Yes. OpenQuok is open source, so you can run it on your own infrastructure (eg. AWS, GCP, Hezner, or even vercel) and manage limits locally without needing a subscription."},{"question":"Can I get a refund?","answer":"With in 1 month, you can get a refund if you have not used the product during a billing period. If you have used the product during a billing period, contact support and we will work with you on a fair resolution. Self-hosted deployments follow your own billing policies."},{"question":"Can I change plans later?","answer":"Yes. Upgrade or downgrade from account billing settings. Proration and timing follow your Stripe subscription when cloud billing is enabled."},{"question":"What is the agent workspace?","answer":"An agent workspace is where you connect channels, schedule posts, and collaborate. Workspaces exist to keep agent and automation context focused. Too many channels or tasks in one place can cause context rot or hallucinations. Use separate workspaces for different brands or clients when things get crowded."},{"question":"What counts as a channel?","answer":"A channel is a connected social account (for example Facebook, Instagram, LinkedIn, TikTok, YouTube, Reddit, Threads, or Pinterest). You schedule posts to the channels you connect."},{"question":"Can I connect 2 channels to the same platform?","answer":"Yes. Example: SOLO plan can connect 15 total accounts, all of them can be tiktok accounts."},{"question":"How does team member work?","answer":"Team members are people you invite to a workspace. They can collaborate on content and connect their own channels where your plan allows. Seat limits are shown as invites plus you as owner. For example, “2 + 1 (you) per workspace” means four invited members and one seat for you on each workspace you own."},{"question":"Will my post get less reach or banned if I use multi-channel publishing with OpenQuok?","answer":"No ! We use the official API for each platform. Your posts should perform the same as if you published them directly on each platform. We had the same concern that algorithms might favor in-app posting, but in our own tests we did not see lower reach when scheduling through OpenQuok."},{"question":"How does repeated posts work","answer":"Repeated posts let you automatically republish evergreen content on a schedule (daily, weekly, or a custom cadence). It’s a great way to keep promoting ongoing offers, quotes, or other timeless content without manually rescheduling."},{"question":"What are reusable templates and how does it work?","answer":"Templates are pre-defined groups of channels with custom message templates. If you frequently post to the same combination of accounts (e.g., your personal X + company LinkedIn + Facebook page), you can save it as a Set for one-click posting."},{"question":"What are reusable signatures and how does it work?","answer":"Signatures are snippets of text you can automatically append to posts (hashtags, links, promos). If you often use the same call-to-action or signature across multiple posts, save it once and reuse it everywhere."},{"question":"What analytics does OpenQuok offer?","answer":"Get detailed analytics across connected platforms—impressions, likes, comments, shares, bookmarks, and engagement rate—so you can track results over time and see what content resonates most."},{"question":"Can I schedule comments or threads","answer":"Yes. You can schedule follow-up comments to help drive engagement. On platforms like X and Threads, you can also schedule full threads, while on LinkedIn and Facebook scheduled comments are posted as replies to your main post."},{"question":"What is the delay feature between posts?","answer":"Use the delay feature to add time gaps between posts and scheduled comments for a more natural publishing cadence—space them out by minutes or hours instead of posting everything at once."},{"question":"I have connnected too many channels, what should I do?","answer":"The Group management feature let you organize connected channels by client, brand, or any structure you like—making it simple to manage multiple clients or keep personal and business accounts separate. This can be selected to create post later or used by smart filters."}]'::jsonb
)
WHERE module_name = 'public_faq'
  AND NOT (config ? 'ITEMS');

COMMIT;
